import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;

public class JsonWriter_value_Boolean_Test {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void value_null_returnsNullValue() throws Exception {
    // Using reflection to get private nullValue method to verify output
    Method nullValueMethod = JsonWriter.class.getDeclaredMethod("nullValue");
    nullValueMethod.setAccessible(true);
    JsonWriter expected = (JsonWriter) nullValueMethod.invoke(jsonWriter);

    JsonWriter result = jsonWriter.value((Boolean) null);

    assertSame(expected, result);
    // nullValue() writes "null"
    assertEquals("null", stringWriter.toString());
  }

  @Test
  public void value_true_writesTrue() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);

    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    JsonWriter returned = spyWriter.value(Boolean.TRUE);

    InOrder inOrder = inOrder(spyWriter);
    inOrder.verify(spyWriter).writeDeferredName();
    inOrder.verify(spyWriter).beforeValue();

    assertSame(spyWriter, returned);
    assertEquals("true", stringWriter.toString());
  }

  @Test
  public void value_false_writesFalse() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);

    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    JsonWriter returned = spyWriter.value(Boolean.FALSE);

    InOrder inOrder = inOrder(spyWriter);
    inOrder.verify(spyWriter).writeDeferredName();
    inOrder.verify(spyWriter).beforeValue();

    assertSame(spyWriter, returned);
    assertEquals("false", stringWriter.toString());
  }
}
